import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';

interface Vara {
  id: number;
  nome: string;
  comarca: string;
  endereco: string;
  telefone: string;
}

const ListaVaras: React.FC = () => {
  const [varas, setVaras] = useState<Vara[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [filtro, setFiltro] = useState<string>('');

  useEffect(() => {
    const fetchVaras = async () => {
      try {
        setLoading(true);
        const response = await axios.get<Vara[]>('/api/varas');
        setVaras(response.data);
        setError(null);
      } catch (err) {
        setError('Erro ao carregar varas. Por favor, tente novamente.');
        console.error('Erro ao buscar varas:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchVaras();
  }, []);

  const varasFiltradas = varas.filter(vara => {
    const termoBusca = filtro.toLowerCase();
    return (
      (vara.nome && vara.nome.toLowerCase().includes(termoBusca)) ||
      (vara.comarca && vara.comarca.toLowerCase().includes(termoBusca)) ||
      (vara.endereco && vara.endereco.toLowerCase().includes(termoBusca))
    );
  });

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-blue-900"></div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded relative" role="alert">
        <strong className="font-bold">Erro!</strong>
        <span className="block sm:inline"> {error}</span>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold text-gray-800">Varas</h1>
        <Link 
          to="/varas/nova" 
          className="bg-blue-900 hover:bg-blue-800 text-white font-bold py-2 px-4 rounded"
        >
          Nova Vara
        </Link>
      </div>

      <div className="mb-6">
        <input
          type="text"
          placeholder="Buscar por nome, comarca ou endereço..."
          className="w-full px-4 py-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
          value={filtro}
          onChange={(e) => setFiltro(e.target.value)}
        />
      </div>

      {varasFiltradas.length === 0 ? (
        <div className="bg-gray-50 p-6 rounded-lg text-center">
          <p className="text-gray-600">Nenhuma vara encontrada.</p>
        </div>
      ) : (
        <div className="overflow-x-auto">
          <table className="min-w-full bg-white border border-gray-200 rounded-lg overflow-hidden">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Nome</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Comarca</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Endereço</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Telefone</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200">
              {varasFiltradas.map((vara) => (
                <tr key={vara.id} className="hover:bg-gray-50">
                  <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">{vara.nome}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{vara.comarca}</td>
                  <td className="px-6 py-4 text-sm text-gray-500">{vara.endereco}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{vara.telefone}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                    <div className="flex space-x-2">
                      <Link to={`/varas/${vara.id}`} className="text-blue-600 hover:text-blue-900">
                        Detalhes
                      </Link>
                      <Link to={`/varas/editar/${vara.id}`} className="text-indigo-600 hover:text-indigo-900">
                        Editar
                      </Link>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default ListaVaras;
